import i18n from '@dhis2/d2-i18n'
import { CheckboxFieldFF } from '@dhis2/ui'
import React from 'react'
import { Field as FieldRFF } from 'react-final-form'
import {
    SectionedFormSection,
    SectionedFormSections,
    StandardFormField,
    StandardFormSectionTitle,
    StandardFormSectionDescription,
    DescriptionField,
    NameField,
    ShortNameField,
    CodeField,
    ValueTypeField,
} from '../../../components'
import {
    useSchemaSectionHandleOrThrow,
    useSyncSelectedSectionWithScroll,
} from '../../../lib'
import { AttributeTypeComponent } from './AttributeTypeComponent'
import { OptionSetField } from './OptionSetField'
import { SortOrderField } from './SortOrderField'

export const AttributeFormFields = ({
    initialValues,
}: {
    initialValues?: Record<string, any>
}) => {
    useSchemaSectionHandleOrThrow()
    useSyncSelectedSectionWithScroll()
    const schemaSection = useSchemaSectionHandleOrThrow()

    return (
        <SectionedFormSections>
            <SectionedFormSection name="basic">
                <StandardFormSectionTitle>
                    {i18n.t('Basic information')}
                </StandardFormSectionTitle>
                <StandardFormSectionDescription>
                    {i18n.t('Set up the basic information for this attribute.')}
                </StandardFormSectionDescription>
                <StandardFormField>
                    <NameField schemaSection={schemaSection} />
                </StandardFormField>

                <StandardFormField>
                    <ShortNameField
                        schemaSection={schemaSection}
                        isRequired={false}
                    />
                </StandardFormField>

                <StandardFormField>
                    <CodeField schemaSection={schemaSection} />
                </StandardFormField>
                <StandardFormField>
                    <DescriptionField />
                </StandardFormField>
            </SectionedFormSection>

            <SectionedFormSection name="data">
                <StandardFormSectionTitle>
                    {i18n.t('Data and options')}
                </StandardFormSectionTitle>
                <StandardFormSectionDescription>
                    {i18n.t(
                        'Configure how this attribute wil be collected, analyzed, and stored.'
                    )}
                </StandardFormSectionDescription>
                <StandardFormField>
                    <OptionSetField />
                </StandardFormField>
                <StandardFormField>
                    <ValueTypeField />
                </StandardFormField>
                <StandardFormField>
                    <SortOrderField />
                </StandardFormField>
                <StandardFormField>
                    <FieldRFF
                        component={CheckboxFieldFF}
                        name="mandatory"
                        label={i18n.t(
                            'Mandatory: all objects must have a value for this attribute'
                        )}
                        type="checkbox"
                        dataTest="formfields-mandatory"
                    />
                </StandardFormField>
                <StandardFormField>
                    <FieldRFF
                        component={CheckboxFieldFF}
                        name="unique"
                        label={i18n.t('Unique values only')}
                        type="checkbox"
                        dataTest="formfields-unique"
                    />
                </StandardFormField>
                <StandardFormField>
                    <AttributeTypeComponent initialValues={initialValues} />
                </StandardFormField>
            </SectionedFormSection>
        </SectionedFormSections>
    )
}
